import { useState, useMemo } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { toast } from 'sonner';
import { formatDate, formatDateTime, formatRelative, parseDateOnly } from '@/utils/dateUtils';
import { Loader2, Settings2, Pencil, Trash2, Users, UserX, UserCheck, KeyRound, SmartphoneNfc, LockOpen, RefreshCw, ShieldCheck, ShieldOff } from 'lucide-react';
import { Button } from '@/shadcn/components/ui/button';
import { Badge } from '@/shadcn/components/ui/badge';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/shadcn/components/ui/tooltip';
import { userService as accountService, type RegistrationPayload } from '@/api/auth/userService';
import { adminService, type UserSecuritySummary } from '@/api/auth/adminService';
import { getApiErrorMessage } from '@/api/app/apiError';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { HarmonyTable, type HarmonyColumn } from '@/components/ui/harmony-table';
import { HarmonyUserProfile } from '@/components/ui/harmony-user-profile';
import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';
import { HarmonyAlertDialog } from '@/components/ui/harmony-alert-dialog';
import { UserFormDialog } from '@/features/users/components/UserFormDialog';
import { ResetPasswordDialog } from '@/features/users/components/ResetPasswordDialog';
import { UserSessionsModal } from '@/features/users/components/UserSessionsModal';
import { useAuth } from '@/shared/AuthContext';
import { queryKeys } from '@/lib/queryKeys';
import { ROUTES } from '@/lib/routes';

import type { User } from '@/types/user';

interface UserFilters {
  status: string;
  userType: string;
  [key: string]: string;
}

const isEmployeeUser = (user: User) => !!user.employeeID && !user.enrollmentId;

const ManageUsers = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const queryClient = useQueryClient();
  const { user: currentUser, hasPermission } = useAuth();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [userType, setUserType] = useState('employee');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isFetchingEdit, setIsFetchingEdit] = useState(false);
  const [selectedUserData, setSelectedUserData] = useState<Record<string, unknown> | null>(null);
  const [userToDelete, setUserToDelete] = useState<User | null>(null);
  const [userToToggle, setUserToToggle] = useState<User | null>(null);
  const [activeUpdatingId, setActiveUpdatingId] = useState<string | null>(null);
  const [userToResetPassword, setUserToResetPassword] = useState<User | null>(null);
  const [userToViewSessions, setUserToViewSessions] = useState<User | null>(null);
  const [unlockingId, setUnlockingId] = useState<string | null>(null);
  const [otpResettingId, setOtpResettingId] = useState<string | null>(null);
  const [userToToggleOtp, setUserToToggleOtp] = useState<User | null>(null);
  const [filterValues, setFilterValues] = useState<UserFilters>({ status: 'active', userType: '' });

  // ── Queries ────────────────────────────────────────────────────────────────

  const { data: employeesData = [], isLoading: isLoadingEmployees, isError: isErrorEmp, error: queryErrorEmp } = useQuery<User[]>({
    queryKey: queryKeys.users.employees(),
    queryFn: () => accountService.getEmployees({ includeInactive: true }),
  });

  const { data: internsData = [], isLoading: isLoadingInterns, isError: isErrorIntern, error: queryErrorIntern } = useQuery<User[]>({
    queryKey: queryKeys.users.interns(),
    queryFn: () => accountService.getInterns({ includeInactive: true }),
  });

  const { data: securityData = [] } = useQuery<UserSecuritySummary[]>({
    queryKey: queryKeys.admin.securitySummary(),
    queryFn: adminService.getUserSecuritySummary,
    staleTime: 60_000,
    retry: (failureCount, error: Error & { response?: { status?: number } }) =>
      error?.response?.status !== 403 && failureCount < 1,
  });

  const securityMap = useMemo(
    () => new Map(securityData.map(s => [s.userId, s])),
    [securityData],
  );

  const isLoading = isLoadingEmployees || isLoadingInterns;
  const isError = isErrorEmp || isErrorIntern;
  const queryError = queryErrorEmp || queryErrorIntern;

  const createDefaultValues = useMemo(
    () => ({ TimeZone: Intl.DateTimeFormat().resolvedOptions().timeZone }),
    [],
  );

  const filteredUsers = useMemo(() => {
    let all = [...employeesData, ...internsData];
    if (filterValues.status === 'active') all = all.filter(u => u.isActive !== false);
    else if (filterValues.status === 'inactive') all = all.filter(u => u.isActive === false);
    if (filterValues.userType === 'employee') all = all.filter(u => isEmployeeUser(u));
    else if (filterValues.userType === 'intern') all = all.filter(u => !isEmployeeUser(u));
    return all;
  }, [employeesData, internsData, filterValues]);

  const invalidate = () => {
    queryClient.invalidateQueries({ queryKey: queryKeys.users.employees() });
    queryClient.invalidateQueries({ queryKey: queryKeys.users.interns() });
  };

  const invalidateSecurity = () =>
    queryClient.invalidateQueries({ queryKey: queryKeys.admin.securitySummary() });

  // ── Mutations ──────────────────────────────────────────────────────────────

  const deleteMutation = useMutation({
    mutationFn: (user: User) => isEmployeeUser(user)
      ? accountService.deleteEmployee(user.id)
      : accountService.deleteIntern(user.id),
    onSuccess: () => {
      invalidate();
      setUserToDelete(null);
      toast.success('User deleted successfully.');
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to delete user.')),
  });

  const activeMutation = useMutation({
    mutationFn: ({ userId, active }: { userId: string; active: boolean }) =>
      adminService.setUserActive(userId, active),
    onSuccess: (_data, variables) => {
      const applyUpdate = (old: User[] | undefined) =>
        old?.map(u => u.id === variables.userId ? { ...u, isActive: variables.active } : u) ?? [];
      queryClient.setQueryData(queryKeys.users.employees(), applyUpdate);
      queryClient.setQueryData(queryKeys.users.interns(), applyUpdate);
      invalidate();
      setUserToToggle(null);
      setActiveUpdatingId(null);
      toast.success(`User ${variables.active ? 'enabled' : 'disabled'} successfully.`);
    },
    onError: (err) => {
      setActiveUpdatingId(null);
      toast.error(getApiErrorMessage(err, 'Failed to update user status.'));
    },
  });

  const resetPasswordMutation = useMutation({
    mutationFn: ({ userId, newPassword }: { userId: string; newPassword: string }) =>
      adminService.resetUserPassword(userId, newPassword),
    onSuccess: () => {
      setUserToResetPassword(null);
      invalidateSecurity();
      toast.success('Password reset successfully. The user has been logged out of all devices.');
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to reset password.')),
  });

  const unlockMutation = useMutation({
    mutationFn: (userId: string) => adminService.unlockUserAccount(userId),
    onMutate: (userId) => setUnlockingId(userId),
    onSuccess: () => { invalidateSecurity(); toast.success('Account unlocked.'); },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to unlock account.')),
    onSettled: () => setUnlockingId(null),
  });

  const resetOtpMutation = useMutation({
    mutationFn: (userId: string) => adminService.resetUserOtpLockout(userId),
    onMutate: (userId) => setOtpResettingId(userId),
    onSuccess: () => { invalidateSecurity(); toast.success('OTP lockout cleared.'); },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to reset OTP lockout.')),
    onSettled: () => setOtpResettingId(null),
  });

  const setOtpEnabledMutation = useMutation({
    mutationFn: ({ userId, enabled }: { userId: string; enabled: boolean }) =>
      accountService.setUserOtpEnabled(userId, enabled),
    onSuccess: (_data, variables) => {
      const applyUpdate = (old: User[] | undefined) =>
        old?.map(u => u.id === variables.userId ? { ...u, otpEnabled: variables.enabled } : u) ?? [];
      queryClient.setQueryData(queryKeys.users.employees(), applyUpdate);
      queryClient.setQueryData(queryKeys.users.interns(), applyUpdate);
      invalidate();
      setUserToToggleOtp(null);
      toast.success(`OTP ${variables.enabled ? 'enabled' : 'disabled'} for user.`);
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to update OTP setting.')),
  });

  // ── Handlers ───────────────────────────────────────────────────────────────

  const handleOpenModal = () => {
    setError(null);
    setEditingId(null);
    setSelectedUserData(null);
    setUserType(hasPermission(PERMISSIONS.Employee.Create) ? 'employee' : 'intern');
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setError(null);
    setEditingId(null);
    setSelectedUserData(null);
  };

  const handleEdit = async (user: User) => {
    setError(null);
    const isEmp = isEmployeeUser(user);
    setUserType(isEmp ? 'employee' : 'intern');
    setEditingId(user.id);
    setSelectedUserData(null);
    setIsModalOpen(true);
    try {
      setIsFetchingEdit(true);
      const data = isEmp
        ? await accountService.getEmployeeById(user.id)
        : await accountService.getInternById(user.id);
      setSelectedUserData(data);
    } catch {
      toast.error('Failed to load user details. Please try again.');
      setIsModalOpen(false);
    } finally {
      setIsFetchingEdit(false);
    }
  };

  const handleSubmit = async (data: Record<string, unknown>) => {
    try {
      setIsSubmitting(true);
      setError(null);
      if (editingId) {
        if (userType === 'employee') {
          await accountService.updateEmployee(editingId, data);
        } else {
          await accountService.updateIntern(editingId, data);
        }
        toast.success('User updated successfully.');
      } else {
        if (userType === 'employee') {
          await accountService.registerEmployee(data as unknown as RegistrationPayload);
        } else {
          await accountService.registerIntern(data as unknown as RegistrationPayload);
        }
        toast.success('User created successfully.');
      }
      handleCloseModal();
      invalidate();
    } catch (err) {
      setError(getApiErrorMessage(err));
    } finally {
      setIsSubmitting(false);
    }
  };

  // ── Columns ────────────────────────────────────────────────────────────────

  const actionsColumn: HarmonyColumn<User> = {
    key: 'actions',
    header: 'Actions',
    width: 200,
    sortable: false,
    resizable: false,
    cellClass: 'rdg-cell-actions',
    renderCell: ({ row }) => (
      <TooltipProvider>
        <div className="flex items-center gap-0.5">
          <PermissionGate permission={PERMISSIONS.User.Read} mode="disable">
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className="text-muted-foreground hover:text-foreground"
                  onClick={(e) => { e.stopPropagation(); navigate(ROUTES.userProfile(row.id), { state: { from: location.pathname } }); }}
                >
                  <Settings2 size={12} />
                </Button>
              </TooltipTrigger>
              <TooltipContent>Configure</TooltipContent>
            </Tooltip>
          </PermissionGate>
          {row.isActive !== false && (
            <PermissionGate permission={isEmployeeUser(row) ? PERMISSIONS.Employee.Update : PERMISSIONS.Intern.Update} mode="disable">
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    size="icon-xs"
                    variant="ghost"
                    className="text-muted-foreground hover:text-foreground"
                    onClick={(e) => { e.stopPropagation(); handleEdit(row); }}
                  >
                    <Pencil size={12} />
                  </Button>
                </TooltipTrigger>
                <TooltipContent>Edit</TooltipContent>
              </Tooltip>
            </PermissionGate>
          )}
          <PermissionGate permission={PERMISSIONS.User.ResetPassword} mode="disable">
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className="text-muted-foreground hover:text-primary hover:bg-primary/10"
                  disabled={currentUser?.id === row.id}
                  onClick={(e) => { e.stopPropagation(); setUserToResetPassword(row); }}
                >
                  <KeyRound size={12} />
                </Button>
              </TooltipTrigger>
              <TooltipContent>Reset Password</TooltipContent>
            </Tooltip>
          </PermissionGate>
          <PermissionGate permission={PERMISSIONS.User.Update} mode="disable">
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  disabled={activeUpdatingId === row.id}
                  className={row.isActive === false
                    ? 'text-muted-foreground hover:text-emerald-600 hover:bg-emerald-50 dark:hover:text-emerald-400 dark:hover:bg-emerald-950/40'
                    : 'text-muted-foreground hover:text-amber-600 hover:bg-amber-50 dark:hover:text-amber-400 dark:hover:bg-amber-950/40'
                  }
                  onClick={(e) => { e.stopPropagation(); setUserToToggle(row); }}
                >
                  {row.isActive === false ? <UserCheck size={12} /> : <UserX size={12} />}
                </Button>
              </TooltipTrigger>
              <TooltipContent>{row.isActive === false ? 'Enable' : 'Disable'}</TooltipContent>
            </Tooltip>
          </PermissionGate>
          <PermissionGate permission={PERMISSIONS.User.ManageOtp} mode="hide">
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className={row.otpEnabled !== false
                    ? 'text-muted-foreground hover:text-amber-600 hover:bg-amber-50 dark:hover:text-amber-400 dark:hover:bg-amber-950/40'
                    : 'text-muted-foreground hover:text-emerald-600 hover:bg-emerald-50 dark:hover:text-emerald-400 dark:hover:bg-emerald-950/40'
                  }
                  onClick={(e) => { e.stopPropagation(); setUserToToggleOtp(row); }}
                >
                  {row.otpEnabled !== false ? <ShieldOff size={12} /> : <ShieldCheck size={12} />}
                </Button>
              </TooltipTrigger>
              <TooltipContent>{row.otpEnabled !== false ? 'Disable OTP' : 'Enable OTP'}</TooltipContent>
            </Tooltip>
          </PermissionGate>
          {securityMap.get(row.id)?.isLockedOut && (
            <PermissionGate permission={PERMISSIONS.User.Update} mode="disable">
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    size="icon-xs"
                    variant="ghost"
                    className="text-muted-foreground hover:text-rose-600 hover:bg-rose-50 dark:hover:text-rose-400 dark:hover:bg-rose-950/40"
                    disabled={unlockingId === row.id}
                    onClick={(e) => { e.stopPropagation(); unlockMutation.mutate(row.id); }}
                  >
                    {unlockingId === row.id
                      ? <Loader2 size={12} className="animate-spin" />
                      : <LockOpen size={12} />
                    }
                  </Button>
                </TooltipTrigger>
                <TooltipContent>Unlock Account</TooltipContent>
              </Tooltip>
            </PermissionGate>
          )}
          {securityMap.get(row.id)?.otpIsLockedOut && (
            <PermissionGate permission={PERMISSIONS.User.Update} mode="disable">
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    size="icon-xs"
                    variant="ghost"
                    className="text-muted-foreground hover:text-amber-600 hover:bg-amber-50 dark:hover:text-amber-400 dark:hover:bg-amber-950/40"
                    disabled={otpResettingId === row.id}
                    onClick={(e) => { e.stopPropagation(); resetOtpMutation.mutate(row.id); }}
                  >
                    {otpResettingId === row.id
                      ? <Loader2 size={12} className="animate-spin" />
                      : <RefreshCw size={12} />
                    }
                  </Button>
                </TooltipTrigger>
                <TooltipContent>Reset OTP Lockout</TooltipContent>
              </Tooltip>
            </PermissionGate>
          )}
          <PermissionGate permission={PERMISSIONS.User.Read} mode="disable">
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className="text-muted-foreground hover:text-primary hover:bg-primary/10"
                  onClick={(e) => { e.stopPropagation(); setUserToViewSessions(row); }}
                >
                  <SmartphoneNfc size={12} />
                </Button>
              </TooltipTrigger>
              <TooltipContent className="space-y-0.5 text-xs">
                <div>Sessions: {securityMap.get(row.id)?.activeSessionCount ?? 0}</div>
                {securityMap.get(row.id)?.lastLoginAt && (
                  <div>Last login: {formatDateTime(securityMap.get(row.id)!.lastLoginAt)}</div>
                )}
                {securityMap.get(row.id)?.passwordLastChangedAt && (
                  <div>Password changed: {formatDateTime(securityMap.get(row.id)!.passwordLastChangedAt)}</div>
                )}
              </TooltipContent>
            </Tooltip>
          </PermissionGate>
          <PermissionGate
            permission={isEmployeeUser(row) ? PERMISSIONS.Employee.Delete : PERMISSIONS.Intern.Delete}
            mode="disable"
          >
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className="text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                  onClick={(e) => { e.stopPropagation(); setUserToDelete(row); }}
                >
                  <Trash2 size={12} />
                </Button>
              </TooltipTrigger>
              <TooltipContent>Delete</TooltipContent>
            </Tooltip>
          </PermissionGate>
        </div>
      </TooltipProvider>
    ),
  };

  const columns: HarmonyColumn<User>[] = [
    {
      key: 'name',
      header: 'Name',
      width: 260,
      sortable: false,
      renderCell: ({ row }) => (
        <HarmonyUserProfile
          user={row}
          onNameClick={() => navigate(ROUTES.userProfile(row.id), { state: { from: location.pathname } })}
          cacheKey={row.profilePictureUrl != null ? undefined : null}
        />
      ),
    },
    {
      key: 'id',
      header: 'ID',
      width: 130,
      sortable: false,
      renderCell: ({ row }) => row.employeeID || row.enrollmentId || 'N/A',
    },
    {
      key: 'userType',
      header: 'Type',
      width: 95,
      sortable: false,
      renderCell: ({ row }) => isEmployeeUser(row)
        ? <Badge variant="outline" className="text-xs border-sky-200 text-sky-700 dark:border-sky-800 dark:text-sky-400">Employee</Badge>
        : <Badge variant="outline" className="text-xs border-violet-200 text-violet-700 dark:border-violet-800 dark:text-violet-400">Intern</Badge>,
    },
    {
      key: 'email',
      header: 'Email',
      fill: true,
      sortable: false,
      renderCell: ({ row }) => row.email || 'N/A',
    },
    {
      key: 'phoneNumber',
      header: 'Phone',
      width: 130,
      sortable: false,
      renderCell: ({ row }) => row.phoneNumber || '—',
    },
    {
      key: 'pan',
      header: 'PAN',
      width: 120,
      sortable: false,
      renderCell: ({ row }) => row.pan || '—',
    },
    {
      key: 'joiningDate',
      header: 'Joining Date',
      width: 120,
      sortable: false,
      renderCell: ({ row }) => formatDate(row.joiningDate),
    },
    {
      key: 'birthDate',
      header: 'Birth Date',
      width: 110,
      sortable: false,
      renderCell: ({ row }) => formatDate(row.birthDate),
    },
    {
      key: 'lastLogin',
      header: 'Last Login',
      width: 150,
      sortable: false,
      renderCell: ({ row }) => {
        const lastLogin = securityMap.get(row.id)?.lastLoginAt;
        return lastLogin
          ? formatRelative(lastLogin)
          : '—';
      },
    },
    {
      key: 'isActive',
      header: 'Status',
      width: 130,
      sortable: false,
      renderCell: ({ row }) => {
        const t = new Date();
        // Normalize both sides to UTC midnight so timezone doesn't cause ±1 day drift.
        const todayUTC    = Date.UTC(t.getFullYear(), t.getMonth(), t.getDate());
        const leavingDate = parseDateOnly(row.leavingDate);
        const leavingUTC  = leavingDate ? Date.UTC(leavingDate.getFullYear(), leavingDate.getMonth(), leavingDate.getDate()) : null;
        const daysUntil  = leavingUTC !== null
          ? Math.ceil((leavingUTC - todayUTC) / 86_400_000)
          : null;
        const isExpired  = row.isActive !== false && daysUntil !== null && daysUntil < 0;
        const expireSoon = row.isActive !== false && daysUntil !== null && daysUntil >= 0 && daysUntil <= 7;
        return (
          <div className="flex items-center gap-1 flex-wrap">
            {(row.isActive !== false)
              ? <Badge variant="outline" className="border-emerald-300 bg-emerald-50 text-emerald-700 dark:border-emerald-800 dark:bg-emerald-950/40 dark:text-emerald-400">Active</Badge>
              : <Badge variant="outline" className="border-rose-300 bg-rose-50 text-rose-600 dark:border-rose-800 dark:bg-rose-950/40 dark:text-rose-400">Disabled</Badge>
            }
            {isExpired && (
              <Badge variant="outline" className="border-rose-300 bg-rose-50 text-rose-600 dark:border-rose-800 dark:bg-rose-950/40 dark:text-rose-400">Expired</Badge>
            )}
            {expireSoon && (
              <Badge variant="outline" className="border-amber-300 bg-amber-50 text-amber-700 dark:border-amber-800 dark:bg-amber-950/40 dark:text-amber-400">
                {daysUntil === 0 ? 'Expires today' : `Exp. ${daysUntil}d`}
              </Badge>
            )}
          </div>
        );
      },
    },
    {
      key: 'otpEnabled',
      header: 'OTP',
      width: 85,
      sortable: false,
      renderCell: ({ row }) => (row.otpEnabled ?? true)
        ? <Badge variant="outline" className="text-xs border-emerald-200 text-emerald-700 dark:border-emerald-800 dark:text-emerald-400">Enabled</Badge>
        : <Badge variant="outline" className="text-xs border-amber-200 text-amber-700 dark:border-amber-800 dark:text-amber-400">Disabled</Badge>,
    },
    actionsColumn,
  ];

  // ── Render ─────────────────────────────────────────────────────────────────

  return (
    <div className="page-wrapper flex flex-col" style={{ gap: 'var(--section-padding)' }}>
      <div className="flex items-center gap-3">
        <div className="size-12 flex items-center justify-center rounded-lg bg-primary/10 shrink-0">
          <Users className="w-7 h-7 text-primary" />
        </div>
        <div>
          <h1 className="page-title">Manage Users</h1>
          <p className="page-subtitle">View, edit, and manage employees and interns</p>
        </div>
      </div>

      <HarmonyTable<User>
        rows={filteredUsers}
        columns={columns}
        rowKeyGetter={(row) => row.id}
        loading={isLoading}
        error={isError ? (queryError as Error) : undefined}

        filterDefs={[
          {
            param: 'status',
            label: 'Status',
            type: 'select',
            options: [
              { value: 'active', label: 'Active' },
              { value: 'inactive', label: 'Inactive' },
            ],
          },
          {
            param: 'userType',
            label: 'User Type',
            type: 'select',
            options: [
              { value: 'employee', label: 'Employee' },
              { value: 'intern', label: 'Intern' },
            ],
          },
        ]}
        filterValues={filterValues}
        onFilterChange={(params) => setFilterValues(prev =>
          Object.fromEntries(Object.keys(prev).map(k => [k, params[k] ?? ''])) as UserFilters
        )}

        searchPlaceholder="Search by name, email, or ID…"

        dataActions={{
          extra: (
            <PermissionGate permission={[PERMISSIONS.Employee.Create, PERMISSIONS.Intern.Create]} requirement="any">
              <Button variant="default" size="sm" onClick={handleOpenModal}>
                Add User
              </Button>
            </PermissionGate>
          ),
        }}
      />

      <UserFormDialog
        open={isModalOpen}
        onClose={handleCloseModal}
        editingId={editingId}
        activeTab={userType}
        userType={userType}
        onUserTypeChange={setUserType}
        isFetchingEdit={isFetchingEdit}
        selectedUserData={selectedUserData}
        createDefaultValues={createDefaultValues}
        error={error}
        isSubmitting={isSubmitting}
        onSubmit={handleSubmit}
      />

      {userToDelete && (
        <HarmonyAlertDialog
          open={!!userToDelete}
          onOpenChange={(open) => { if (!open) setUserToDelete(null); }}
          variant="danger"
          title="Delete User"
          description={`This will permanently remove ${userToDelete.fullName || userToDelete.firstName || 'this user'} from the system. This action cannot be undone.`}
          actionLabel="Permanently Delete"
          onAction={() => deleteMutation.mutate(userToDelete)}
          isActioning={deleteMutation.isPending}
        />
      )}

      {userToToggle && (
        <HarmonyAlertDialog
          open={!!userToToggle}
          onOpenChange={(open) => { if (!open) setUserToToggle(null); }}
          variant={userToToggle.isActive === false ? 'default' : 'warning'}
          title={userToToggle.isActive === false ? 'Enable User Account' : 'Disable User Account'}
          description={
            userToToggle.isActive === false
              ? `This will re-enable ${userToToggle.fullName || userToToggle.firstName || 'this user'}'s account. They will be able to log in again.`
              : `This will disable ${userToToggle.fullName || userToToggle.firstName || 'this user'}'s account. They will no longer be able to log in. Switch the Status filter to Inactive to find and re-enable them.`
          }
          actionLabel={userToToggle.isActive === false ? 'Enable Account' : 'Disable Account'}
          onAction={() => {
            const willEnable = userToToggle.isActive === false;
            setActiveUpdatingId(userToToggle.id);
            activeMutation.mutate({ userId: userToToggle.id, active: willEnable });
          }}
          isActioning={activeMutation.isPending}
        />
      )}

      <ResetPasswordDialog
        open={!!userToResetPassword}
        onOpenChange={(open) => { if (!open) setUserToResetPassword(null); }}
        userName={userToResetPassword?.fullName || userToResetPassword?.firstName || 'this user'}
        onSubmit={(newPassword) =>
          resetPasswordMutation.mutateAsync({ userId: userToResetPassword?.id ?? '', newPassword })
        }
        isSubmitting={resetPasswordMutation.isPending}
      />

      {userToToggleOtp && (
        <HarmonyAlertDialog
          open={!!userToToggleOtp}
          onOpenChange={(open) => { if (!open) setUserToToggleOtp(null); }}
          variant={userToToggleOtp.otpEnabled !== false ? 'warning' : 'default'}
          title={userToToggleOtp.otpEnabled !== false ? 'Disable OTP' : 'Enable OTP'}
          description={
            userToToggleOtp.otpEnabled !== false
              ? `This will disable OTP login for ${userToToggleOtp.fullName || userToToggleOtp.firstName || 'this user'}. They will be able to log in with password only.`
              : `This will enable OTP login for ${userToToggleOtp.fullName || userToToggleOtp.firstName || 'this user'}. They will be required to verify a one-time code on each login.`
          }
          actionLabel={userToToggleOtp.otpEnabled !== false ? 'Disable OTP' : 'Enable OTP'}
          onAction={() =>
            setOtpEnabledMutation.mutate({ userId: userToToggleOtp.id, enabled: userToToggleOtp.otpEnabled === false })
          }
          isActioning={setOtpEnabledMutation.isPending}
        />
      )}

      <UserSessionsModal
        open={!!userToViewSessions}
        onOpenChange={(open) => { if (!open) setUserToViewSessions(null); }}
        userId={userToViewSessions?.id ?? ''}
        userName={userToViewSessions?.fullName || userToViewSessions?.firstName || 'this user'}
        onRevokedAll={invalidateSecurity}
      />
    </div>
  );
};

export default ManageUsers;
