import { useState, useEffect } from 'react';
import { Eye, EyeOff } from 'lucide-react';
import { Input } from '@/shadcn/components/ui/input';
import { Label } from '@/shadcn/components/ui/label';
import { HarmonyDialog } from '@/components/ui/harmony-dialog';
import { usePasswordPolicy, validatePassword } from '@/lib/passwordUtils';
import { getApiErrorMessage } from '@/api/app/apiError';

interface ResetPasswordDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  userName: string;
  onSubmit: (newPassword: string) => Promise<void>;
  isSubmitting: boolean;
}

export const ResetPasswordDialog = ({
  open,
  onOpenChange,
  userName,
  onSubmit,
  isSubmitting,
}: ResetPasswordDialogProps) => {
  const { data: passwordPolicy } = usePasswordPolicy();
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!open) return;
    setNewPassword('');
    setConfirmPassword('');
    setError('');
    setShowNew(false);
    setShowConfirm(false);
  }, [open]);

  const handleOpenChange = (open: boolean) => {
    if (isSubmitting) return;
    onOpenChange(open);
  };

  const handleSubmit = async () => {
    setError('');
    if (!newPassword) { setError('Password is required.'); return; }
    const policyError = passwordPolicy ? validatePassword(newPassword, passwordPolicy) : null;
    if (policyError) { setError(policyError); return; }
    if (!confirmPassword) { setError('Confirm password is required.'); return; }
    if (newPassword !== confirmPassword) {
      setError('Passwords do not match.');
      return;
    }
    try {
      await onSubmit(newPassword);
    } catch (err: unknown) {
      setError(getApiErrorMessage(err, 'Failed to reset password. Please try again.'));
    }
  };

  return (
    <HarmonyDialog
      open={open}
      onOpenChange={handleOpenChange}
      title="Reset Password"
      description={`Set a new password for ${userName}. Their current sessions will be revoked immediately.`}
      size="md"
      onSubmit={handleSubmit}
      submitLabel="Reset Password"
      isSubmitting={isSubmitting}
    >
      <div className="space-y-4">
        {[
          { label: 'New Password',     value: newPassword,     setValue: setNewPassword,     show: showNew,     toggle: () => setShowNew(s => !s),     placeholder: passwordPolicy ? `Min. ${passwordPolicy.minLength} characters` : '' },
          { label: 'Confirm Password', value: confirmPassword, setValue: setConfirmPassword, show: showConfirm, toggle: () => setShowConfirm(s => !s), placeholder: 'Repeat new password' },
        ].map(({ label, value, setValue, show, toggle, placeholder }) => (
          <div key={label} className="space-y-1.5">
            <Label>{label}</Label>
            <div className="relative">
              <Input
                type={show ? 'text' : 'password'}
                value={value}
                onChange={(e) => setValue(e.target.value)}
                placeholder={placeholder}
                className="pr-10"
              />
              <button
                type="button"
                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                onClick={toggle}
              >
                {show ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>
        ))}
        {error && <p className="text-sm text-destructive">{error}</p>}
      </div>
    </HarmonyDialog>
  );
};
